INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00373', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '我國憲法第23條規定，第二章所列舉之自由權利，除為防止妨礙他人自由、避免緊急危難、維持社 會秩序，或增進公共利益所必要者外，不得以法律限制之。換言之，倘若是為防止妨礙他人自由、避 免緊急危難、維持社會秩序，或增進公共利益所必要者，則得以法律限制之。此種法律解釋方法為下 列何者？', '["歷史解釋", "反面解釋", "合憲解釋", "目的解釋"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00374', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '關於憲法第15條所保障之財產權，下列敘述何者正確？', '["得主張財產權的主體僅限於自然人與法人，非法人團體由於沒有權利能力，因此不得享有財產權", "人民之財產具有社會義務性，因此縱使超過忍受義務範圍，亦無權請求國家予以補償", "都市更新影響人民財產權甚鉅，因此都市更新之辦理應遵循正當法律程序，確保利害關係人知悉及 適時陳述意見之機會", "行政機關依法作成土地徵收處分，既屬合法且為公益目的所必要，則縱使遲延發給補償金，亦不影 響徵收處分之效力，人民僅能提起訴訟請求補償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00375', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '下列與特別權力關係相關之大法官解釋，何者正確？', '["各級學校學生認其權利因學校之教育或管理等公權力措施而遭受侵害時，即使非屬退學或類此之處 分，亦得向法院提起訴訟", "受羈押之刑事被告，得依羈押法向看守所提出申訴，已屬充分保障其救濟權利，因此未許其向法院 提起訴訟仍屬合憲", "現役軍人縱於非戰時犯罪，除依陸海空軍刑法論處外，考量軍事安全與軍人的訴訟權益，該案件仍 應歸屬軍事法院審理", "教師認其權利或法律上利益因學校具體措施遭受侵害時，倘若其教師身分未有變動，則考量法院負 擔而僅能依學校內部程序提起申訴，不得提起訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00376', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '知名小說家龍老先生，與第一任妻子甲婚後育有一子乙，並收養一女丙，但又與婚外情對象丁女育有 一女戊，龍老先生年邁時立下一份遺囑。若依我國相關法律之規定，下列關於上述案例之相關敘述， 何者錯誤？', '["龍老先生法定繼承人為甲、乙、丙、戊", "龍老先生的遺囑內容，不可違反民法特留分規定", "龍老先生著作的「姓名表示權」可由子女繼承", "著作財產權的保障期間至龍先生逝世後50年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00377', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '原住民族依據紀念日及節日實施辦法相關規定，可以在公告的歲時祭儀放假日期放假一天，此作法是 保障原住民族的何項權利？', '["自由權", "財產權", "社會權", "文化權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00378', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '司法院釋字第749號解釋：「……僅以計程車駕駛人所觸犯之罪及經法院判決有期徒刑以上之刑為要 件，而不問其犯行是否足以顯示對乘客安全具有實質風險，均吊扣其執業登記證、廢止其執業登記， 就此而言，已逾越必要程度。」請問涉及違反下列那一原則？', '["比例原則", "信賴保護原則", "法律保留原則", "誠實信用原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00379', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '某建設公司銷售預售屋，要求消費者先付訂金方可帶回買賣契約書審閱，此舉遭公平交易委員會認定 違反公平交易法第25條規定，繼而裁處該案之建商及代銷業者各新臺幣100萬元及50萬元罰鍰。下 列敘述何者正確？', '["建商及代銷業者所受之懲處屬行政罰，若不服該懲處可向高等法院提出訴願", "消費者有權將買賣契約書帶回審閱，係因題述之買賣行為屬「訪問買賣」", "建商與代銷業者共同侵害消費者權益，違反公平交易法結合行為之規定", "公平交易法屬「成文法」與「經濟行政法」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00380', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '刑法對於犯罪行為的構成要件有相關規範，但如果是明文規定的「阻卻違法事由」，因不具違法性， 則刑法不會處罰。下列何者非刑法規定的「阻卻違法事由」？', '["警察為追捕犯罪嫌疑人，開車時超速不慎擦撞到機車騎士害其滑倒受傷", "路人用石頭敲碎車窗，救出因天氣炎熱已呈現昏迷狀態受困車內的小孩", "在私人拳擊場上，拳擊手在賽後毆打對手，造成對方臉部瘀青出血", "醫師依家屬意見和腦死病人生前簽訂放棄急救同意書，為其拔除呼吸器"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00381', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', 'Johnsurprisedeveryonebysayinghewould hismillion-dollarjobthenextday.', '["quit", "pay", "delay", "treat"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00382', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', 'ObservewhatIdo ,andyouwillseewhatImean.', '["nearly", "closely", "barely", "namely"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
